// RecentPostsGrid.js

import React from "react";

export const RecentPostsGrid = ({
  data,
  headerName,
  renderRecentPosts,
  isTwoCols = false,
  isThreeCols = false,
}) => {
  let gridColsClass = "mdx-rc-gd-one";
  if (isTwoCols) {
    gridColsClass = "mdx-rc-gd-two";
  } else if (isThreeCols) {
    gridColsClass = "mdx-rc-gd-three";
  }

  const renderedPosts = renderRecentPosts(data); // Render recent posts

  return (
    <section className="mdx-rc-wrp">
      <h4 title={headerName} style={{fontStyle:"normal"}}>{headerName}</h4>
      {renderedPosts.length > 0 ? ( // Check if there are rendered posts
        <article className={`mdx-rc-gd ${gridColsClass} `}>
          {renderedPosts}
        </article>
      ) : (
        <article className="mdx-rc-nd">n.d.</article>
      )}
    </section>
  );
};
