// TocWrp.js

import React, { useState } from "react";
import { renderToc } from "./renderToc";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import { faChevronDown, faChevronUp } from "@fortawesome/free-solid-svg-icons";
import { HrGeneral } from "src/utils/HorizontalRules";

export const TocWrp = ({ tableOfContents }) => {
  const [isOpen, setIsOpen] = useState(false);

  const toggleCollapse = () => {
    setIsOpen(!isOpen);
  };

  const handleKeyPress = (event) => {
    if (event.key === "Enter") {
      toggleCollapse();
    }
  };

  return (
    <div
      tabIndex="0"
      role="button"
      onClick={toggleCollapse}
      onKeyPress={handleKeyPress}
      className="mdx-toc-flx"
    >
      <div className="mdx-toc-wrp">
        <div className="mdx-toc-head-wrp">
          <div title="Contents" className="mdx-toc-tit">
            Contents
          </div>
          <div className="mdx-toc-ico">
            {isOpen ? (
              <>
                <span>Show </span>
                <FontAwesomeIcon icon={faChevronUp} />
              </>
            ) : (
              <>
                <span>Hide </span>
                <FontAwesomeIcon icon={faChevronDown} />
              </>
            )}
          </div>
        </div>

        {/* Render the TOC based on the isOpen state */}
        {isOpen && <HrGeneral />}

        {/* Render the TOC based on the isOpen state */}
        {isOpen && renderToc(tableOfContents)}
      </div>
    </div>
  );
};
