export const generateBibTeXString = (data, entryType, entryValue) => {
  const bibtexData = {
    title: data?.mdx?.frontmatter?.title || "",
    author: Array.isArray(data?.mdx?.frontmatter?.author)
      ? data.mdx.frontmatter.author
          .map((author) => {
            const [firstname, lastname] = author.name.split(" ");
            return `${lastname}, ${firstname}`;
          })
          .join(" and ")
      : "",
    journal: data?.mdx?.frontmatter?.journal || "",
    year: data?.mdx?.frontmatter?.year || "",
    day: data?.mdx?.frontmatter?.day || "",
    month: data?.mdx?.frontmatter?.month || "",
    issn: data?.mdx?.frontmatter?.issn || "",
    doi: data?.mdx?.frontmatter?.doi || "",
    url: data?.mdx?.frontmatter?.url || "",
    note: data?.mdx?.frontmatter?.note || "",
    language: data?.mdx?.frontmatter?.language || "",
    shorttitle: data?.mdx?.frontmatter?.title_short || "",
    pages: data?.mdx?.frontmatter?.pages || "",
    abstract: data?.mdx?.frontmatter?.abstract || "",
  };

  return `@${entryType}{${entryValue},
      title = {${bibtexData.title}},
      author = {${bibtexData.author}},
      journal = {${bibtexData.journal}},
      year = {${bibtexData.year}},
      month = {${bibtexData.month}},
      day = {${bibtexData.day}},
      issn = {${bibtexData.issn}},
      doi = {${bibtexData.doi}},
      url = {${bibtexData.url}},
      note = {${bibtexData.note}},
      language = {${bibtexData.language}},
      shorttitle = {${bibtexData.shorttitle}},
      pages = {${bibtexData.pages}},
      abstract = {${bibtexData.abstract}},
    }`;
};
