// RecentPostsWrp.js

import React from "react";
import { HrGeneral, HrLoose } from "src/utils/HorizontalRules";
import { RecentPostsWrp } from "./RecentPostsWrp";

// prettier-ignore
export const RecentPosts = ({ data }) => {
  const { p_type } = data.mdx.frontmatter;

  const componentsMap = {
    projects: ["projects", "pub", "models"],
    pub: ["pub", "models"],
    blog: ["blog", "projects", "models", "news"],
    models: ["models", "projects"],
    news: ["news", "projects"],
    papers: [],  // No need to render anything for 'papers' (for now)
    archive: []  // No need to render anything for 'archive' (for now)
  };

  const orderedComponents = componentsMap[p_type] || [];

  const renderRecentPosts = (componentOrder, data) => {
    if (componentOrder.length > 0) {
      return componentOrder.map((type, index) => (
        <div key={index}>
          <RecentPostsWrp p_type={type} allMdx={data.allMdx} currentPostTitle={data.mdx.frontmatter.title} />
          {index !== componentOrder.length - 1 && <HrGeneral />}
        </div>
      ));
    }
    return null;
  };

  return (
    <>
      {orderedComponents.length > 0 && (
        <>
          <HrLoose />
          <section className="mdx-rc-all">
            {renderRecentPosts(orderedComponents, data)}
          </section>
        </>
      )}
    </>
  );
}
