// FrontmatterFields.js

import { formatKeywords } from "./formatKeywords";
import { formatSoftwares } from "./formatSoftwares";

export const FrontmatterFields = ({ data }) => {
  const renderFields = [];

  if (
    data.mdx.frontmatter.p_type === "archive" ||
    data.mdx.frontmatter.p_type === "models" ||
    data.mdx.frontmatter.p_type === "papers" ||
    data.mdx.frontmatter.p_type === "blog"
  ) {
    renderFields.push(
      { key: "Date", value: data.mdx.frontmatter.date || "" },
      {
        key: "Keywords",
        value: formatKeywords(data.mdx.frontmatter.keywords),
      },
    );
  }

  if (data.mdx.frontmatter.p_type === "news") {
    renderFields.push(
      { key: "Date", value: data.mdx.frontmatter.date || null },
      { key: "Publisher", value: data.mdx.frontmatter.publisher || null },
      {
        key: "Author(s)",
        value:
          Array.isArray(data?.mdx?.frontmatter?.author) &&
          data.mdx.frontmatter.author.map((author) => author.name).join(", "),
      },
      {
        key: "Editor(s)",
        value:
          Array.isArray(data?.mdx?.frontmatter?.editor) &&
          data.mdx.frontmatter.editor.map((editor) => editor.name).join(", "),
      },
    );
  }

  if (data.mdx.frontmatter.p_type === "projects") {
    renderFields.push(
      { key: "Keywords", value: formatKeywords(data.mdx.frontmatter.keywords) },
      { key: "Location", value: data.mdx.frontmatter.location },
      { key: "Type", value: data.mdx.frontmatter.pr_type },
      { key: "Contributor", value: data.mdx.frontmatter.pr_contributor },
      { key: "Contribution", value: data.mdx.frontmatter.pr_contribution },
      { key: "Software", value: formatSoftwares(data.mdx.frontmatter.software) },
      { key: "Advisor", value: data.mdx.frontmatter.pr_adv },
      { key: "Jury", value: data.mdx.frontmatter.pr_jury },
      { key: "Team Leader", value: data.mdx.frontmatter.pr_tl },
      { key: "Instructor", value: data.mdx.frontmatter.pr_instructor },
    );
  }

  return renderFields;
};
