// FrontmatterFieldsPub.js

import React from "react";
import { formatAuthors } from "./formatAuthors";
import { formatKeywords } from "./formatKeywords";

export const FrontmatterFieldsPubBot = ({ data }) => {
  return [
    { key: "ISSN", value: data?.mdx?.frontmatter?.issn },
    { key: "Pages", value: data?.mdx?.frontmatter?.pages },
    { key: "Copyright", value: data?.mdx?.frontmatter?.copyright },
  ];
};

export const FrontmatterFieldsPubTop = ({ data }) => {
  return [
    {
      key: "DOI",
      value: data?.mdx?.frontmatter?.doi && (
        <div className="mdx-fm-wrp-val-doi">
          <a
            href={`https://doi.org/${data.mdx.frontmatter.doi}`}
            className="g-normal-link"
          >
            {data.mdx.frontmatter.doi}
          </a>
        </div>
      ),
    },
    {
      key: "Author(s)",
      value: formatAuthors(data?.mdx?.frontmatter?.author),
    },
    { key: "Journal", value: data?.mdx?.frontmatter?.journal },
    { key: "Publisher", value: data?.mdx?.frontmatter?.publisher },
    { key: "Publication date", value: data?.mdx?.frontmatter?.date },
    { key: "Keywords", value: formatKeywords(data.mdx.frontmatter.keywords) },
    {
      key: "Cite",
      value: data?.mdx?.frontmatter?.cite_article && (
        <div className="mdx-fm-wrp-val-cite">
          {data.mdx.frontmatter.cite_article}
        </div>
      ),
    },
  ];
};
