// MdxFrontmatter.js

import React from "react";
import { renderFrontmatterField } from "./render-fields/renderFrontmatterField";

import { FrontmatterFields } from "./render-fields/FrontmatterFields";
import {
  FrontmatterFieldsPubTop,
  FrontmatterFieldsPubBot,
} from "./render-fields/FrontmatterFieldsPub";
import { BibTeXComponent } from "./render-fields/bibtex/BibTeXComponent";

export const MdxFrontmatter = ({ data }) => {
  return (
    <div className="mdx-fm-wrp">
      {data.mdx.frontmatter.p_type === "pub" ? (
        <>
          {/* Field (top) */}
          {FrontmatterFieldsPubTop({ data }).map((field, index) => (
            <React.Fragment key={`top-${field.key}-${index}`}>
              {renderFrontmatterField(field.key, field.value, field.extraClass)}
            </React.Fragment>
          ))}

          {/* BibTeX: Button */}
          <BibTeXComponent />

          {/* Field (bottom) */}
          {FrontmatterFieldsPubBot({ data }).map((field, index) => (
            <React.Fragment key={`bot-${field.key}-${index}`}>
              {renderFrontmatterField(field.key, field.value, field.extraClass)}
            </React.Fragment>
          ))}
        </>
      ) : (
        <>
          {FrontmatterFields({ data }).map((field, index) => (
            <React.Fragment key={`${field.key}-${index}`}>
              {renderFrontmatterField(field.key, field.value, field.extraClass)}
            </React.Fragment>
          ))}
        </>
      )}
    </div>
  );
};
