// renderFrontmatterField.js

import React from "react";

export const renderFrontmatterField = (key, value, extraClass) => {
  if (!value) return null;
  return (
    <div>
      <div className="mdx-fm-wrp-key">{key}:</div>
      <div className={`mdx-fm-wrp-val${extraClass ? ` ${extraClass}` : ""}`}>
        {value}
      </div>
    </div>
  );
};
