// renderToc.js

import React from "react";

export const renderToc = (items) => {
  return (
    <>
      <div className="mdx-toc-ul-wrp">
        {items.map((item) => (
          <ul key={item.title}>
            <li>
              <a title={item.title} className="g-glow-link" href={item.url}>
                {item.title}
              </a>
              {/* Check if item has children */}
              {item.items && (
                <ul>
                  {item.items.map((childItem) => (
                    <li key={childItem.title}>
                      <a
                        title={childItem.title}
                        className="g-glow-link"
                        href={childItem.url}
                      >
                        {childItem.title}
                      </a>
                      {/* Check if childItem has grandchildren */}
                      {childItem.items && (
                        <ul>
                          {childItem.items.map((grandchildItem) => (
                            <li key={grandchildItem.title}>
                              <a
                                title={grandchildItem.title}
                                className="g-glow-link"
                                href={grandchildItem.url}
                              >
                                {grandchildItem.title}
                              </a>
                            </li>
                          ))}
                        </ul>
                      )}
                    </li>
                  ))}
                </ul>
              )}
            </li>
          </ul>
        ))}
      </div>
    </>
  );
};
