import { useEffect, useState } from "react";

export const useToc = (data) => {
  const [tableOfContents, setTableOfContents] = useState([]);

  useEffect(() => {
    // Extract the table of contents from data.mdx.tableOfContents
    setTableOfContents(data.mdx.tableOfContents.items || []);
  }, [data.mdx.tableOfContents]);

  return tableOfContents;
};
