// MdxPostTemplate.js

import React, { useState, useEffect } from "react";
import { GatsbyImage, getImage } from "gatsby-plugin-image";
import { useToc } from "./toc/useToc";
import { TocWrp } from "./toc/TocWrp";
import { MdxFrontmatter } from "./frontmatter/MdxFrontmatter";
import { RecentPosts } from "./recent-posts/RecentPosts";
import { HrLoose, HrGeneral } from "src/utils/HorizontalRules";

export const MdxPostTemplate = ({ data, children }) => {
  const image = getImage(data.mdx.frontmatter.hero_img_src);
  const tableOfContents = useToc(data);
  const [isTablet, setIsTablet] = useState(false);

  useEffect(() => {
    const handleResize = () => {
      setIsTablet(window.innerWidth < 1024);
    };

    handleResize();
    window.addEventListener("resize", handleResize);

    return () => {
      window.removeEventListener("resize", handleResize);
    };
  }, []);

  return (
    <>
      {/* Content */}
      <section id="___mdx">
        {/* Title */}
        {data.mdx.frontmatter.title && (
          <h1
            className={`mdx-tit${data.mdx.frontmatter.title_sub ? " has-tit-sub" : ""}`}
          >
            {data.mdx.frontmatter.title}
          </h1>
        )}

        {/* Short title (sub) */}
        {data.mdx.frontmatter.title_sub && (
          <p className="mdx-tit-sub">{data.mdx.frontmatter.title_sub}</p>
        )}

        {/* Hero image */}
        {(data.mdx.frontmatter.p_type === "projects" ||
          data.mdx.frontmatter.p_type === "blog" ||
          data.mdx.frontmatter.p_type === "news") &&
          (data.mdx.frontmatter.hero_img_src ? (
            <div
              className={`mdx-img${data.mdx.frontmatter.p_type === "blog" && data.mdx.frontmatter.hero_img_alt ? " with-img-crd" : ""}`}
            >
              <GatsbyImage
                image={image}
                alt={data.mdx.frontmatter.hero_img_alt || ""}
                className={`${data.mdx.frontmatter.p_type === "projects" ? "mdx-img-gat-inv" : "mdx-img-gat-bsc"}`}
              />
            </div>
          ) : null)}

        {/* News only */}
        {data.mdx.frontmatter.p_type === "news" && (
          <>
            {/* TL;DR */}

            {data.mdx.frontmatter.abstract && (
              <blockquote className="mdx-notes">
                <p>
                  <b>TD;LR</b> — {data.mdx.frontmatter.abstract}
                </p>
              </blockquote>
            )}

            {/* Archiving-statement */}
            {data.mdx.frontmatter.url && (
              <blockquote className="mdx-notes">
                <p>
                  This content is preserved here for archival purposes. All
                  rights to the content belong to the original creators. For
                  more information, please see our{" "}
                  <a href="/notes#archiving-statement">Archiving Statement</a>.
                </p>
                <p>
                  You can view the original content at:{" "}
                  <a href={data.mdx.frontmatter.url}>
                    {data.mdx.frontmatter.url}
                  </a>
                </p>
              </blockquote>
            )}
          </>
        )}

        {/* Frontmatter */}
        {data.mdx.frontmatter.p_type && <MdxFrontmatter data={data} />}

        {/* Table of contents */}
        {(data.mdx.frontmatter.p_type === "blog" ||
          data.mdx.frontmatter.p_type === "pub" ||
          data.mdx.frontmatter.p_type === "projects") &&
          tableOfContents &&
          tableOfContents.length > 0 && (
            <TocWrp tableOfContents={tableOfContents} />
          )}

        {/* Abstract */}
        {data.mdx.frontmatter.p_type === "projects" &&
          data.mdx.frontmatter.abstract && (
            <>
              <h1>Abstract</h1>
              <p
                title="Abstract"
                style={{ paddingTop: "2rem", paddingBottom: "2rem" }}
              >
                {data.mdx.frontmatter.abstract}
              </p>
            </>
          )}

        {/* Conditional rendering of horizontal rules */}
        {isTablet ? <HrGeneral /> : <HrLoose />}

        {/* Main content */}
        {children && children}

        {/* RecentPosts data */}
        <RecentPosts data={data} />
      </section>
    </>
  );
};
