// formatAuthors.js

import React from "react";
import { faOrcid } from "@fortawesome/free-brands-svg-icons";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";

export const formatAuthors = (authors) => {
  if (!authors) return null;

  return (
    <div className="mdx-fm-wrp-val-aut">
      {authors.map((author, index) => (
        <React.Fragment key={index}>
          {author.name === "Arnott Ferels" ? (
            <div style={{ textWrap: "nowrap" }}>
              <a href="/about" className="g-normal-link ">
                {author.name}
              </a>{" "}
              <a
                href="https://orcid.org/0000-0003-4733-8175"
                target="_blank"
                rel="noopener noreferrer"
              >
                <FontAwesomeIcon icon={faOrcid} className="g-ico-orcid" />
              </a>
            </div>
          ) : (
            <div style={{ textWrap: "nowrap" }}>{author.name}</div>
          )}
          {index < authors.length - 1 && <span>,&nbsp;</span>}
        </React.Fragment>
      ))}
    </div>
  );
};
