import React, { useState, useEffect } from "react";
import { BibTeXButton } from "./BibTeXButton";

import { generateBibTeXString } from "./BibTeXGenerator";
import { extractFrontmatter } from "./extractFrontmatter";
import { handleCopyToClipboard } from "./handleCopyToClipboard";

export const BibTeXComponent = ({ data }) => {
  const [showBibTeX, setShowBibTeX] = useState(false);
  const [isMobile, setIsMobile] = useState(false);

  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth < 768);
    };

    handleResize();
    window.addEventListener("resize", handleResize);

    return () => {
      window.removeEventListener("resize", handleResize);
    };
  }, []);

  const { entryType, entryValue } = extractFrontmatter(data);

  const bibTeXString = generateBibTeXString(data, entryType, entryValue);

  const handleCopy = () => {
    handleCopyToClipboard(bibTeXString);
  };

  return (
    <div key="BibTeX" className="mdx-bib-flx">
      <div className="mdx-bib-wrp">
        <div className="mdx-bib-head">BibTeX:</div>

        {/* Conditional rendering based on isMobile state */}
        {isMobile ? (
          <BibTeXButton onClick={handleCopy} text="Copy BibTeX" />
        ) : (
          <div className="mdx-bib-btn-desktop">
            {/* Show/Hide button */}
            <BibTeXButton
              onClick={() => setShowBibTeX(!showBibTeX)}
              text={showBibTeX ? "Hide" : "Show"} // Changed text here
              extraClass="mdx-bib-btn-ec-show"
            />
            {/* Copy BibTeX button */}
            {showBibTeX && (
              <BibTeXButton onClick={handleCopy} text="Copy BibTeX" />
            )}
          </div>
        )}
      </div>

      {/* BibTeX: String */}
      {!isMobile && showBibTeX && (
        <div
          title="Click to select the BibTeX entry"
          className="mdx-bib-value-desktop"
        >
          {bibTeXString}
        </div>
      )}
    </div>
  );
};
