import { useStaticQuery, graphql } from "gatsby";

export const PostQuery = ({ postType }) => {
  const data = useStaticQuery(graphql`
    query PostsQuery {
      allMdx(sort: { frontmatter: { date: DESC } }) {
        edges {
          node {
            id
            excerpt
            frontmatter {
              p_type
              title
              slug
              date
              abstract
              author {
                id
                name
              }
              hero_img_src {
                childImageSharp {
                  gatsbyImageData
                }
              }
            }
          }
        }
      }
    }
  `);

  return data.allMdx.edges.filter(
    (edge) => edge.node.frontmatter.p_type === postType,
  );
};
