// RecentPosts.js

import React from "react";
import { PostQuery } from "./PostQuery";
import { RecentPostsGrid } from "src/templates/recent-posts/RecentPostsGrid";
import { RecentPostsCard } from "src/templates/recent-posts/RecentPostsCard";

const getHeaderName = (type) => {
  switch (type) {
    case "blog":
      return "Recent Blogs";
    case "models":
      return "Recent Models";
    case "news":
      return "Recent News";
    case "projects":
      return "Recent Projects";
    case "pub":
      return "Recent Publications";
    default:
      return "Recent Posts";
  }
};

const getRecentPosts = (posts, currentPostTitle) => {
  return posts
    .filter(({ node }) => node.frontmatter.title !== currentPostTitle)
    .slice(0, 6);
};

export const RecentPostsWrp = ({ p_type, allMdx, currentPostTitle }) => {
  const posts = PostQuery({ postType: p_type });
  const recentPosts = getRecentPosts(posts, currentPostTitle);
  const isTwoCols = p_type === "models" || p_type === "projects";

  return (
    <RecentPostsGrid
      headerName={getHeaderName(p_type)}
      renderRecentPosts={() => RecentPostsCard(recentPosts)}
      data={allMdx}
      isTwoCols={isTwoCols}
    />
  );
};
