// formatSoftwares.js

import React from "react";

export const formatSoftwares = (softwares) => {
  if (!Array.isArray(softwares)) return null;

  const visibleSoftwares = softwares.slice(0, 5);

  return (
    <div className="g-kw-wrp-fm">
      {visibleSoftwares.map((software, index) => (
        <React.Fragment key={index}>
          <a
            href={`/search/?q=${encodeURIComponent(software.name)}`}
            className="g-kw-btn"
            title={software.name}
          >
            {software.name}
          </a>
          {index < visibleSoftwares.length - 1 && " "}
        </React.Fragment>
      ))}
    </div>
  );
};
