// RecentPostsCard.js

import React from "react";
import { Link } from "gatsby";
import { GatsbyImage, getImage } from "gatsby-plugin-image";
import { ReadMoreLink } from "src/utils/ReadMoreLinks";
import PlaceholderImage from "src/assets/placeholder/2000x2000.png";

// Function to determine author or publisher based on p_type
const getAuthorOrPublisher = (node) => {
  if (node.frontmatter.p_type === "news") {
    return node.frontmatter.publisher || null;
  } else if (Array.isArray(node.frontmatter.author)) {
    return node.frontmatter.author.map((author) => author.name).join(", ");
  } else {
    return node.frontmatter.author || null;
  }
};

const getTruncatedAbstract = (node) => {
  const abstract = node.frontmatter.abstract;

  if (!abstract) {
    return null;
  }

  const maxLength = 300;

  if (abstract.length > maxLength) {
    return abstract.substring(0, maxLength) + " ...";
  }

  return abstract;
};

export const RecentPostsCard = (RecentPosts) => {
  return RecentPosts.map(({ node }) => {
    const image = getImage(node.frontmatter.hero_img_src);
    const authorOrPublisher = getAuthorOrPublisher(node);
    const truncatedAbstract = getTruncatedAbstract(node);

    return (
      <div
        key={node.id}
        // className="mdx-rc-card-wrp"
        className="pg-cd-bsc-gview"
        title={node.frontmatter.title}
      >
        {/* Hero image */}
        <div className="rc-img-wrp">
          <Link to={`/${node.frontmatter.p_type}/${node.frontmatter.slug}`}>
            {node.frontmatter.hero_img_src ? (
              <GatsbyImage
                title={node.frontmatter.title}
                image={image}
                alt={
                  node.frontmatter.hero_img_alt
                    ? node.frontmatter.hero_img_alt
                    : node.frontmatter.title
                }
                className="rc-img img-not-drk"
              />
            ) : (
              <img
                alt="Placeholder"
                src={PlaceholderImage}
                title={node.frontmatter.title}
                className="rc-img img-inv-drk"
              />
            )}
          </Link>
        </div>

        {/* Frontmatter */}
        <div className="rc-fm-wrp">
          {/* Title */}
          <div className="rc-fm-tit">
            <Link
              to={`/${node.frontmatter.p_type}/${node.frontmatter.slug}`}
              className="g-hidden-link"
            >
              {node.frontmatter.title}
            </Link>
          </div>
          {/* Author or Publisher */}
          {authorOrPublisher && (
            <p className="rc-fm-aop" title={authorOrPublisher}>
              {authorOrPublisher}
            </p>
          )}
          {/* Abstract */}
          {node.frontmatter.p_type === "pub" && node.frontmatter.abstract && (
            <p className="rc-fm-abs" title={node.frontmatter.abstract}>
              {truncatedAbstract}
            </p>
          )}

          {/* Read more link */}
          <div className="g-rml-wrp">
            <ReadMoreLink
              slug={node.frontmatter.slug}
              pType={node.frontmatter.p_type}
            />
          </div>
        </div>
      </div>
    );
  });
};
