// formatKeywords.js

import React from "react";

export const formatKeywords = (keywords) => {
  if (!Array.isArray(keywords)) return null;

  const visibleKeywords = keywords.slice(0, 5);

  return (
    <div className="g-kw-wrp-fm">
      {visibleKeywords.map((keyword, index) => (
        <React.Fragment key={index}>
          <a
            href={`/search/?q=${encodeURIComponent(keyword.name)}`}
            className="g-kw-btn"
            title={keyword.name}
          >
            {keyword.name}
          </a>
          {index < visibleKeywords.length - 1 && " "}
        </React.Fragment>
      ))}
    </div>
  );
};
